vector<int> findNextGreaterElement(vector<int>& subsetNumbers, vector<int>& fullNumbers) {
    unordered_map<int,int> nextGreaterMap;
    stack<int> st;
    for (int num : fullNumbers) {
        while (!st.empty() && st.top() < num) {
            nextGreaterMap[st.top()] = num;
            st.pop();
        }
        st.push(num);
    }
    while (!st.empty()) {
        nextGreaterMap[st.top()] = -1;
        st.pop();
    }
    vector<int> result;
    result.reserve(subsetNumbers.size());
    for (int num : subsetNumbers) {
        result.push_back(nextGreaterMap[num]);
    }
    return result;
}

