int* findNextGreaterElement(int* subsetNumbers, int subsetNumbersLength, int* fullNumbers, int fullNumbersLength, int* resultLength) {
    int *stack = (int*)malloc(fullNumbersLength * sizeof(int));
    int top = -1;
    int *map = (int*)malloc(10001 * sizeof(int));
    for (int i = 0; i <= 10000; i++) map[i] = -1;
    for (int i = fullNumbersLength - 1; i >= 0; i--) {
        while (top >= 0 && stack[top] <= fullNumbers[i]) top--;
        map[fullNumbers[i]] = top < 0 ? -1 : stack[top];
        stack[++top] = fullNumbers[i];
    }
    int *ans = (int*)malloc(subsetNumbersLength * sizeof(int));
    for (int i = 0; i < subsetNumbersLength; i++) ans[i] = map[subsetNumbers[i]];
    free(stack);
    free(map);
    *resultLength = subsetNumbersLength;
    return ans;
}

