function findNextGreaterElement(subsetNumbers, fullNumbers) {
  const stack = [];
  const nextGreaterMap = new Map();
  for (let num of fullNumbers) {
    while (stack.length && stack[stack.length - 1] < num) {
      nextGreaterMap.set(stack.pop(), num);
    }
    stack.push(num);
  }
  while (stack.length) {
    nextGreaterMap.set(stack.pop(), -1);
  }
  return subsetNumbers.map(num => nextGreaterMap.get(num));
}
